const API_KEY = 'your_api_key_here';
const BASE_URL = 'https://api.limiter.io/v1';

async function createRateLimitRule(projectId, rule) {
  const response = await fetch(`${BASE_URL}/projects/${projectId}/rules`, {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${API_KEY}`,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify(rule),
  });
  return response.json();
}

createRateLimitRule('project_id', {
  name: 'my-rule',
  route: '/api/*',
  max_req: 100,
  window_ms: 60000,
}).then(console.log);
